const appMetrics = {
  arpu: 1480,
  churnRate: 0.04,
  cpi: 2500
};

function calcLTV(arpu, churnRate) {
  return arpu * (1 / churnRate);
}

function calcPaybackPeriod(cpi, arpu) {
  return cpi / arpu;
}

function isViable(ltv, cpi) {
  return ltv >= cpi * 3;
}

const ltv = calcLTV(appMetrics.arpu, appMetrics.churnRate);
const payback = calcPaybackPeriod(appMetrics.cpi, appMetrics.arpu);
console.log('LTV:', '¥' + ltv.toFixed(0));
console.log('CPI回収期間:', payback.toFixed(1) + 'ヶ月');
console.log('ビジネス成立性:', isViable(ltv, appMetrics.cpi) ? '健全' : '要改善');
